import type { Angle, Area, Length, ScalarQuantity } from "../../../core/quantity.js";
import type { AreaUnit, LengthUnit } from "../../../core/units.js";
import type { InputUnitInfos } from "../sketch/types.js";

/** @since 5.0 */
export type TooltipMode = "feedback" | "input";

/** @internal */
export type TooltipFieldName = "area" | "direction" | "distance" | "elevation" | "orientation" | "radius" | "rotation" | "scale" | "size" | "totalLength" | "x" | "y";

/** @since 5.0 */
export type TooltipDirectionMode = "relative" | "absolute";

/**
 * Formatting functions which can be used by fields to format their values into strings.
 *
 * @internal
 */
export interface Formatters {
  /** @internal */
  angleRelative: (value: number) => string;
  /** @internal */
  direction: (value: Angle) => string;
  /** @internal */
  directionRelative: (value: Angle) => string;
  /** @internal */
  directionRelativeBilateral: (value: Angle) => string;
  /** @internal */
  latitudeDecimalDegrees: (value: Angle) => string;
  /** @internal */
  longitudeDecimalDegrees: (value: Angle) => string;
  /** @internal */
  area: (value: Area, unit?: AreaUnit | null) => string;
  /** @internal */
  length: (value: Length, unit?: LengthUnit | null, precision?: number | null) => string;
  /** @internal */
  lengthRelative: (value: Length, unit?: LengthUnit | null) => string;
  /** @internal */
  percentage: (value: ScalarQuantity) => string;
  /** @internal */
  scalar: (value: ScalarQuantity) => string;
  /** @internal */
  scale: (value: number) => string;
  /** @internal */
  totalLength: (value: Length, unit?: LengthUnit | null) => string;
  /** @internal */
  verticalLength: (value: Length, unit?: LengthUnit | null) => string;
  /** @internal */
  verticalLengthRelative: (value: Length, unit?: LengthUnit | null) => string;
}

/**
 * Tooltip field context which can be used to
 *
 * @internal
 */
export interface TooltipFieldContext {
  /** @internal */
  inputUnitInfos: InputUnitInfos;
}